// harness 给的是 div 容器；先创建真实 input，再动态加载 TomSelect
const el = document.getElementById('select'); const input = document.createElement('input'); el.appendChild(input);
const css = document.createElement('link'); css.rel = 'stylesheet'; css.href = 'https://cdn.jsdelivr.net/npm/tom-select@2.6.2/dist/css/tom-select.css'; document.head.appendChild(css);
const { default: TomSelect } = await import('https://cdn.jsdelivr.net/npm/tom-select@2/+esm');
const control = new TomSelect(input, { options: data.options, items: data.items ?? [], valueField: data.valueField ?? 'value', labelField: data.labelField ?? 'text', searchField: data.searchField ?? ['text'], maxItems: data.maxItems ?? null, create: data.create ?? false, plugins: data.plugins ?? [], placeholder: data.placeholder });

